import { 
  type User, 
  type InsertUser,
  type ContactInquiry,
  type InsertContactInquiry,
  type QuoteRequest,
  type InsertQuoteRequest
} from "@shared/schema";
import { randomUUID } from "crypto";

export interface SiteContent {
  hero: {
    badge: string;
