    body2: 'Our "beyond the brief" approach keeps customer satisfaction at the core of everything we do — delivering impeccable service within agreed timeframes for both government and private organizations.',
  },
}

export function useSiteContent() {
  const { data, isLoading, error } = useQuery<SiteContent>({
    queryKey: ["/api/content"],
    queryFn: async () => {
      const res = await fetch("/api/content")
      const json = await res.json()
      if (json.success) return json.data
      throw new Error(json.message)
    },
    staleTime: 30_000,
    placeholderData: defaultContent,
  })

  return {
    content: data ?? defaultContent,
    isLoading,
    error,
  }
}

export function useUpdateSiteContent() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (updates: Partial<SiteContent>) => {
      const res = await fetch("/api/admin/content", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updates),
      })
      const json = await res.json()
      if (!json.success) throw new Error(json.message)
      return json.data as SiteContent
    },
    onSuccess: (data) => {
      queryClient.setQueryData(["/api/content"], data)
    },
  })
}

import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { ThemeProvider } from "@/components/ThemeProvider";
import EnhancedNavigation from "@/components/EnhancedNavigation";
import EnhancedHero from "@/components/EnhancedHero";
import Services from "@/components/Services";
import About from "@/components/About";
import WhyChooseUs from "@/components/WhyChooseUs";
import Training from "@/components/Training";
import CustomerSatisfaction from "@/components/CustomerSatisfaction";
import CaretakerResponsibilities from "@/components/CaretakerResponsibilities";
import Testimonials from "@/components/Testimonials";
import FAQ from "@/components/FAQ";
import Contact from "@/components/Contact";
import Footer from "@/components/Footer";
import FloatingQuoteButton from "@/components/FloatingQuoteButton";
import AdminPage from "@/pages/AdminPage";
import NotFound from "@/pages/not-found";

function HomePage() {
  return (
    <div className="min-h-screen bg-background">
      <EnhancedNavigation />
      <main>
        <EnhancedHero />
        <Services />
        <WhyChooseUs />
        <About />
        <Training />
        <CustomerSatisfaction />
        <CaretakerResponsibilities />
        <Testimonials />
        <FAQ />
        <Contact />
      </main>
      <FloatingQuoteButton />
      <Footer />
    </div>
  );
}

function Router() {
  return (
    <Switch>
      <Route path="/" component={HomePage} />
      <Route path="/admin" component={AdminPage} />
      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <ThemeProvider defaultTheme="light">
          <Toaster />
          <Router />
        </ThemeProvider>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

